context-view.source:
"use client"

import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

const contextViewVariants = cva("flex flex-col px-4 py-4", {
  variants: {
    variant: {
      full: "gap-4",
      withActions: "gap-4",
      withLink: "gap-1",
      minimal: "gap-1",
    },
  },
  defaultVariants: {
    variant: "full",
  },
})

export interface ContextViewProps
  extends Omit<React.HTMLAttributes<HTMLDivElement>, "title">,
    VariantProps<typeof contextViewVariants> {
  /** Main title (e.g. "Drawer title") */
  title?: React.ReactNode
  /** Secondary text below the title */
  description?: React.ReactNode
  /** Optional link (e.g. "Optional link" with icon). Shown when variant is `full` or `withLink`. */
  link?: React.ReactNode
  /** Primary action button. Shown when variant is `full` or `withActions`. */
  primaryAction?: React.ReactNode
  /** Secondary action button. Shown when variant is `full` or `withActions`. */
  secondaryAction?: React.ReactNode
}

const ContextView = React.forwardRef<HTMLDivElement, ContextViewProps>(
  (
    {
      className,
      variant = "full",
      title,
      description,
      link,
      primaryAction,
      secondaryAction,
      children,
      ...props
    },
    ref
  ) => {
    const showLink = (variant === "full" || variant === "withLink") && link != null
    const showActions =
      (variant === "full" || variant === "withActions") &&
      (primaryAction != null || secondaryAction != null)

    return (
      <div
        ref={ref}
        data-slot="context-view"
        data-variant={variant}
        className={cn(contextViewVariants({ variant }), className)}
        {...props}
      >
        {title != null && (
          <span className="text-base font-semibold text-foreground">
            {title}
          </span>
        )}
        {description != null && (
          <span className="text-sm text-muted-foreground">{description}</span>
        )}
        {showLink && <div className="pt-0.5">{link}</div>}
        {showActions && (
          <div className="flex flex-col gap-2">
            {primaryAction}
            {secondaryAction}
          </div>
        )}
        {children}
      </div>
    )
  }
)
ContextView.displayName = "ContextView"

export { ContextView, contextViewVariants }

data-table.source:
"use client";

import * as React from "react";
import {
  type ColumnDef,
  type Header,
  type HeaderGroup,
  type Row,
  type Cell,
  flexRender,
  getCoreRowModel,
  getPaginationRowModel,
  useReactTable,
} from "@tanstack/react-table";

import { Button } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { MoreHorizontal } from "lucide-react";

export type Payment = {
  id: string;
  amount: number;
  status: "pending" | "processing" | "success" | "failed";
  email: string;
};

export const payments: Payment[] = [
  { id: "728ed52f", amount: 100, status: "pending", email: "m@example.com" },
  { id: "489e1d42", amount: 125, status: "processing", email: "example@gmail.com" },
  { id: "924ed52f", amount: 316, status: "success", email: "ken99@example.com" },
  { id: "a1be1d42", amount: 242, status: "success", email: "Abe45@example.com" },
  { id: "b34ed52f", amount: 837, status: "processing", email: "Monserrat44@example.com" },
  { id: "c4ce1d42", amount: 874, status: "success", email: "Silas22@example.com" },
  { id: "d56ed52f", amount: 721, status: "failed", email: "carmella@example.com" },
];

export const paymentColumns: ColumnDef<Payment>[] = [
  {
    accessorKey: "status",
    header: "Status",
  },
  {
    accessorKey: "email",
    header: "Email",
  },
  {
    accessorKey: "amount",
    header: () => <div className="text-right">Amount</div>,
    cell: ({ row }: { row: Row<Payment> }) => {
      const amount = parseFloat(row.getValue("amount"));
      const formatted = new Intl.NumberFormat("en-US", {
        style: "currency",
        currency: "USD",
      }).format(amount);
      return <div className="text-right font-medium">{formatted}</div>;
    },
  },
  {
    id: "actions",
    cell: ({ row }: { row: Row<Payment> }) => {
      const payment = row.original;
      return (
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <Button variant="secondary" size="sm" className="h-8 w-8 p-0">
              <span className="sr-only">Open menu</span>
              <MoreHorizontal className="h-4 w-4" />
            </Button>
          </DropdownMenuTrigger>
          <DropdownMenuContent align="end">
            <DropdownMenuLabel>Actions</DropdownMenuLabel>
            <DropdownMenuItem
              onClick={() => navigator.clipboard.writeText(payment.id)}
            >
              Copy payment ID
            </DropdownMenuItem>
            <DropdownMenuSeparator />
            <DropdownMenuItem>View customer</DropdownMenuItem>
            <DropdownMenuItem>View payment details</DropdownMenuItem>
          </DropdownMenuContent>
        </DropdownMenu>
      );
    },
  },
];

interface DataTableProps<TData, TValue> {
  columns: ColumnDef<TData, TValue>[];
  data: TData[];
}

export function DataTable<TData, TValue>({
  columns,
  data,
}: DataTableProps<TData, TValue>) {
  const table = useReactTable({
    data,
    columns,
    getCoreRowModel: getCoreRowModel(),
    getPaginationRowModel: getPaginationRowModel(),
  });

  return (
    <div className="space-y-4">
      <div className="overflow-hidden rounded-md border border-border-neutral">
        <Table>
          <TableHeader>
            {table.getHeaderGroups().map((headerGroup: HeaderGroup<TData>) => (
              <TableRow key={headerGroup.id}>
                {headerGroup.headers.map((header: Header<TData, unknown>) => (
                  <TableHead key={header.id}>
                    {header.isPlaceholder
                      ? null
                      : flexRender(
                          header.column.columnDef.header,
                          header.getContext()
                        )}
                  </TableHead>
                ))}
              </TableRow>
            ))}
          </TableHeader>
          <TableBody>
            {table.getRowModel().rows?.length ? (
              table.getRowModel().rows.map((row: Row<TData>) => (
                <TableRow
                  key={row.id}
                  data-state={row.getIsSelected() && "selected"}
                >
                  {row.getVisibleCells().map((cell: Cell<TData, unknown>) => (
                    <TableCell key={cell.id}>
                      {flexRender(
                        cell.column.columnDef.cell,
                        cell.getContext()
                      )}
                    </TableCell>
                  ))}
                </TableRow>
              ))
            ) : (
              <TableRow>
                <TableCell
                  colSpan={columns.length}
                  className="h-24 text-center"
                >
                  No results.
                </TableCell>
              </TableRow>
            )}
          </TableBody>
        </Table>
      </div>
      <div className="flex items-center justify-end gap-2">
        <Button
          variant="secondary"
          size="sm"
          onClick={() => table.previousPage()}
          disabled={!table.getCanPreviousPage()}
        >
          Previous
        </Button>
        <Button
          variant="secondary"
          size="sm"
          onClick={() => table.nextPage()}
          disabled={!table.getCanNextPage()}
        >
          Next
        </Button>
      </div>
    </div>
  );
}

data-table14.source:
"use client";

import * as React from "react";
import {
  type ColumnDef,
  type Header,
  type HeaderGroup,
  type Row,
  type Cell,
  flexRender,
  getCoreRowModel,
  getFilteredRowModel,
  getPaginationRowModel,
  getSortedRowModel,
  useReactTable,
  type SortingState,
} from "@tanstack/react-table";
import { ArrowDown, ArrowUp, ChevronsUpDown } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import {
  NativeSelect,
  NativeSelectOption,
} from "@/components/ui/native-select";

export type OrderFilterRow = {
  id: string;
  orderId: string;
  customer: string;
  orderStatus: string;
  paymentStatus: string;
  total: string;
};

const defaultData: OrderFilterRow[] = [
  {
    id: "1",
    orderId: "ORD-101",
    customer: "Alice",
    orderStatus: "Processing",
    paymentStatus: "Paid",
    total: "$120",
  },
  {
    id: "2",
    orderId: "ORD-102",
    customer: "Bob",
    orderStatus: "Shipped",
    paymentStatus: "Paid",
    total: "$85",
  },
  {
    id: "3",
    orderId: "ORD-103",
    customer: "Carol",
    orderStatus: "Pending",
    paymentStatus: "Pending",
    total: "$200",
  },
  {
    id: "4",
    orderId: "ORD-104",
    customer: "Dave",
    orderStatus: "Delivered",
    paymentStatus: "Paid",
    total: "$56",
  },
  {
    id: "5",
    orderId: "ORD-105",
    customer: "Eve",
    orderStatus: "Processing",
    paymentStatus: "Failed",
    total: "$340",
  },
];

export function DataTable14({
  data = defaultData,
}: {
  data?: OrderFilterRow[];
}) {
  const [sorting, setSorting] = React.useState<SortingState>([]);
  const [globalFilter, setGlobalFilter] = React.useState("");
  const [orderStatusFilter, setOrderStatusFilter] =
    React.useState<string>("all");
  const [paymentFilter, setPaymentFilter] = React.useState<string>("all");

  const filteredData = React.useMemo(() => {
    return data.filter((row) => {
      if (orderStatusFilter !== "all" && row.orderStatus !== orderStatusFilter)
        return false;
      if (paymentFilter !== "all" && row.paymentStatus !== paymentFilter)
        return false;
      return true;
    });
  }, [data, orderStatusFilter, paymentFilter]);

  const columns: ColumnDef<OrderFilterRow>[] = React.useMemo(
    () => [
      { accessorKey: "orderId", header: "Order" },
      { accessorKey: "customer", header: "Customer" },
      {
        accessorKey: "orderStatus",
        header: "Order status",
        cell: ({ row }) => (
          <Badge variant="secondary">{row.original.orderStatus}</Badge>
        ),
      },
      {
        accessorKey: "paymentStatus",
        header: "Payment",
        cell: ({ row }) => (
          <Badge
            variant={
              row.original.paymentStatus === "Paid"
                ? "positive"
                : row.original.paymentStatus === "Failed"
                  ? "negative"
                  : "secondary"
            }
          >
            {row.original.paymentStatus}
          </Badge>
        ),
      },
      {
        accessorKey: "total",
        header: "Total",
        cell: ({ row }) => (
          <span className="tabular-nums">{row.original.total}</span>
        ),
      },
    ],
    [],
  );

  const table = useReactTable({
    data: filteredData,
    columns,
    state: { sorting, globalFilter },
    onSortingChange: setSorting,
    onGlobalFilterChange: setGlobalFilter,
    getCoreRowModel: getCoreRowModel(),
    getFilteredRowModel: getFilteredRowModel(),
    getPaginationRowModel: getPaginationRowModel(),
    getSortedRowModel: getSortedRowModel(),
  });

  const orderCounts = React.useMemo(() => {
    const counts: Record<string, number> = { all: data.length };
    data.forEach((r) => {
      counts[r.orderStatus] = (counts[r.orderStatus] ?? 0) + 1;
    });
    return counts;
  }, [data]);

  return (
    <div className="space-y-4 rounded-lg border border-border bg-background p-4">
      <div>
        <h2 className="text-lg font-semibold">Orders</h2>
        <p className="text-sm text-muted-foreground">
          Filter by order status, payment status, and search.
        </p>
      </div>
      <Tabs
        value={orderStatusFilter}
        onValueChange={setOrderStatusFilter}
        className="w-full"
      >
        <TabsList className="mb-2">
          <TabsTrigger value="all">All ({orderCounts.all})</TabsTrigger>
          <TabsTrigger value="Processing">
            Processing ({orderCounts.Processing ?? 0})
          </TabsTrigger>
          <TabsTrigger value="Shipped">
            Shipped ({orderCounts.Shipped ?? 0})
          </TabsTrigger>
          <TabsTrigger value="Pending">
            Pending ({orderCounts.Pending ?? 0})
          </TabsTrigger>
          <TabsTrigger value="Delivered">
            Delivered ({orderCounts.Delivered ?? 0})
          </TabsTrigger>
        </TabsList>
      </Tabs>
      <div className="flex flex-wrap gap-2">
        <Button
          variant={paymentFilter === "all" ? "primary" : "secondary"}
          size="sm"
          onClick={() => setPaymentFilter("all")}
        >
          All
        </Button>
        <Button
          variant={paymentFilter === "Paid" ? "primary" : "secondary"}
          size="sm"
          onClick={() => setPaymentFilter("Paid")}
        >
          Paid
        </Button>
        <Button
          variant={paymentFilter === "Pending" ? "primary" : "secondary"}
          size="sm"
          onClick={() => setPaymentFilter("Pending")}
        >
          Pending
        </Button>
        <Button
          variant={paymentFilter === "Failed" ? "primary" : "secondary"}
          size="sm"
          onClick={() => setPaymentFilter("Failed")}
        >
          Failed
        </Button>
        <Input
          placeholder="Search..."
          className="ml-auto h-8 w-[180px]"
          value={globalFilter}
          onChange={(e) => setGlobalFilter(e.target.value)}
        />
      </div>
      <div className="overflow-x-auto rounded-md border border-border">
        <Table>
          <TableHeader>
            {table
              .getHeaderGroups()
              .map((headerGroup: HeaderGroup<OrderFilterRow>) => (
                <TableRow key={headerGroup.id}>
                  {headerGroup.headers.map(
                    (header: Header<OrderFilterRow, unknown>) => {
                      const canSort = header.column.getCanSort();
                      const sorted = header.column.getIsSorted();
                      return (
                        <TableHead key={header.id}>
                          {canSort ? (
                            <Button
                              variant="primary"
                              size="sm"
                              className="-ml-3 h-8 gap-1"
                              onClick={() =>
                                header.column.toggleSorting(sorted === "asc")
                              }
                            >
                              {header.isPlaceholder
                                ? null
                                : flexRender(
                                    header.column.columnDef.header,
                                    header.getContext(),
                                  )}
                              {sorted === "desc" ? (
                                <ArrowDown className="size-4" />
                              ) : sorted === "asc" ? (
                                <ArrowUp className="size-4" />
                              ) : (
                                <ChevronsUpDown className="size-4 opacity-50" />
                              )}
                            </Button>
                          ) : header.isPlaceholder ? null : (
                            flexRender(
                              header.column.columnDef.header,
                              header.getContext(),
                            )
                          )}
                        </TableHead>
                      );
                    },
                  )}
                </TableRow>
              ))}
          </TableHeader>
          <TableBody>
            {table.getRowModel().rows.map((row: Row<OrderFilterRow>) => (
              <TableRow key={row.id}>
                {row
                  .getVisibleCells()
                  .map((cell: Cell<OrderFilterRow, unknown>) => (
                    <TableCell key={cell.id}>
                      {flexRender(
                        cell.column.columnDef.cell,
                        cell.getContext(),
                      )}
                    </TableCell>
                  ))}
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </div>
      <div className="flex flex-wrap items-center justify-between gap-2">
        <div className="flex items-center gap-2 text-sm text-muted-foreground">
          <span>Rows per page</span>
          <NativeSelect
            className="w-16"
            value={String(table.getState().pagination.pageSize)}
            onChange={(e) => table.setPageSize(Number(e.target.value))}
          >
            <NativeSelectOption value="5">5</NativeSelectOption>
            <NativeSelectOption value="10">10</NativeSelectOption>
            <NativeSelectOption value="20">20</NativeSelectOption>
          </NativeSelect>
          <span>
            {table.getState().pagination.pageIndex *
              table.getState().pagination.pageSize +
              1}
            -
            {Math.min(
              (table.getState().pagination.pageIndex + 1) *
                table.getState().pagination.pageSize,
              table.getFilteredRowModel().rows.length,
            )}{" "}
            of {table.getFilteredRowModel().rows.length}
          </span>
        </div>
        <div className="flex gap-1">
          <Button
            variant="secondary"
            size="sm"
            onClick={() => table.previousPage()}
            disabled={!table.getCanPreviousPage()}
          >
            Previous
          </Button>
          <Button
            variant="secondary"
            size="sm"
            onClick={() => table.nextPage()}
            disabled={!table.getCanNextPage()}
          >
            Next
          </Button>
        </div>
      </div>
    </div>
  );
}

