const parseCurrency = (value: string) =>
  Number(value.replace(/[^0-9.-]+/g, "")) || 0;

export const validatedData = CustomerRecordSchema.array().parse(
  rawOrders.map((order) => {
    const parsedItems = order.items.map((item) => ({
      ...item,
      price: parseCurrency(item.price),
    }));
    const totalItems = parsedItems.reduce(
      (acc, item) => acc + item.quantity,
      0,
    );

    return {
      id: order.id,
      latestOrder: order.orderNumber,
      customer: {
        name: order.customer,
        email: order.customerEmail,
        avatar: order.customerAvatar,
      },
      total: parseCurrency(order.total),
      totalItems,
      status: order.status,
      items: parsedItems,
    };
  }),
);

const currencyFormatter = new Intl.NumberFormat("en-US", {
  style: "currency",
  currency: "USD",
});

const statusBadgeClassMap: Record<StatusVariant, string> = {
  info: "border-sky-200 bg-sky-50 text-sky-700",
  primary: "border-violet-200 bg-violet-50 text-violet-700",
  success: "border-emerald-200 bg-emerald-50 text-emerald-700",
  warning: "border-amber-200 bg-amber-50 text-amber-700",
  destructive: "border-rose-200 bg-rose-50 text-rose-700",
};

const getStatusBadgeClasses = (variant: StatusVariant) =>
  statusBadgeClassMap[variant] ?? statusBadgeClassMap.info;

const avatarColorClasses = [
  "bg-slate-100 text-slate-700",
  "bg-emerald-100 text-emerald-700",
  "bg-indigo-100 text-indigo-700",
  "bg-amber-100 text-amber-700",
  "bg-rose-100 text-rose-700",
  "bg-sky-100 text-sky-700",
];

const getAvatarColor = (value: string) => {
  const hash = value
    .split("")
    .reduce((acc, char) => acc + char.charCodeAt(0), 0);

  return avatarColorClasses[hash % avatarColorClasses.length];
};

const getInitials = (name: string) => {
  const parts = name.trim().split(" ");
  const first = parts[0]?.charAt(0) ?? "";
  const second = parts[1]?.charAt(0) ?? parts[0]?.charAt(1) ?? "";
  return `${first}${second}`.toUpperCase();
};

export type StatusOption = {
  label: string;
  value: string;
  icon?: React.ComponentType<{ className?: string }>;
};

export const orderStatuses: StatusOption[] = [
  { label: "Processing", value: "Processing", icon: LoaderIcon },
  { label: "Shipped", value: "Shipped", icon: Truck },
  { label: "Delivered", value: "Delivered", icon: CheckCircle },
  { label: "Pending", value: "Pending", icon: Clock },
  { label: "Cancelled", value: "Cancelled", icon: XCircle },
];

const createStatusLookup = (options: StatusOption[]) =>
  options.reduce<Record<string, StatusOption>>((acc, option) => {
    acc[option.value] = option;
    return acc;
  }, {});

const orderStatusLookup = createStatusLookup(orderStatuses);

export const getOrderStatusMeta = (status: string) => orderStatusLookup[status];

// Sub-table component for order items
function OrderItemsSubTable({ items }: { items: OrderItem[] }) {
  const [sorting, setSorting] = React.useState<SortingState>([]);
  const [pagination, setPagination] = React.useState<PaginationState>({
    pageIndex: 0,
    pageSize: 5,
  });

  const columns = React.useMemo<ColumnDef<OrderItem>[]>(
    () => [
      {
        accessorKey: "productName",
        header: ({ column }) => (
          <DataTableColumnHeader column={column} title="Product" />
        ),
        cell: (info) => (
          <span className="text-sm font-medium">
            {info.getValue() as string}
          </span>
        ),
        enableSorting: true,
      },
      {
        accessorKey: "category",
        header: ({ column }) => (
          <DataTableColumnHeader column={column} title="Category" />
        ),
        cell: (info) => (
          <span className="text-sm text-muted-foreground">
            {info.getValue() as string}
          </span>
        ),
        enableSorting: true,
      },
      {
        accessorKey: "quantity",
        header: ({ column }) => (
          <DataTableColumnHeader column={column} title="Qty" />
        ),
        cell: (info) => (
          <span className="text-sm font-medium tabular-nums">
            {info.getValue() as number}
          </span>
        ),
        meta: { align: "right", className: "tabular-nums" },
        enableSorting: true,
      },
      {
        accessorKey: "price",
        header: ({ column }) => (
          <DataTableColumnHeader column={column} title="Price" />
        ),
        cell: (info) => (
          <span className="text-sm font-semibold tabular-nums">
            {currencyFormatter.format(info.getValue() as number)}
          </span>
        ),
        meta: { align: "right", className: "tabular-nums" },
        enableSorting: true,
      },
    ],
    [],
  );

  const table = useReactTable({
    data: items,
    columns,
    pageCount: Math.ceil(items.length / pagination.pageSize),
    state: {
      sorting,
      pagination,
    },
    onSortingChange: setSorting,
    onPaginationChange: setPagination,
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: getSortedRowModel(),
    getPaginationRowModel: getPaginationRowModel(),
    getRowId: (row: OrderItem) => row.id,
  });

  return (
    <div className="rounded-lg bg-muted/30 p-4">
      <div className="mb-3 flex items-center justify-between">
        <h4 className="text-sm font-semibold">Order items</h4>
        <Badge variant="outline" className="text-xs">
          {items.length} {items.length === 1 ? "item" : "items"}
        </Badge>
      </div>
      <div className="rounded-md border bg-background">
        <Table>
          <TableHeader>
            {table.getHeaderGroups().map((headerGroup) => (
              <TableRow key={headerGroup.id} className="bg-muted/50">
                {headerGroup.headers.map((header) => (
                  <TableHead key={header.id} className="h-9">
                    {header.isPlaceholder
                      ? null
                      : flexRender(
                          header.column.columnDef.header,
                          header.getContext(),
                        )}
                  </TableHead>
                ))}
              </TableRow>
            ))}
          </TableHeader>
          <TableBody>
            {table.getRowModel().rows?.length ? (
              table.getRowModel().rows.map((row) => (
                <TableRow
                  key={row.id}
                  className="transition-colors hover:bg-muted/50"
                >
                  {row.getVisibleCells().map((cell) => (
                    <TableCell key={cell.id} className="py-2">
                      {flexRender(
                        cell.column.columnDef.cell,
                        cell.getContext(),
                      )}
                    </TableCell>
                  ))}
                </TableRow>
              ))
            ) : (
              <TableRow>
                <TableCell
                  colSpan={columns.length}
                  className="h-16 text-center text-sm text-muted-foreground"
                >
                  No order history.
                </TableCell>
              </TableRow>
            )}
          </TableBody>
        </Table>
      </div>
      {items.length > pagination.pageSize && (
        <div className="mt-3 flex items-center justify-between px-2">
          <div className="text-xs text-muted-foreground">
            Showing {table.getRowModel().rows.length} of {items.length} items
          </div>
          <div className="flex gap-2">
            <Button
              variant="primary"
              size="sm"
              onClick={() => table.previousPage()}
              disabled={!table.getCanPreviousPage()}
            >
              Previous
            </Button>
            <Button
              variant="primary"
              size="sm"
              onClick={() => table.nextPage()}
              disabled={!table.getCanNextPage()}
            >
              Next
            </Button>
          </div>
        </div>
      )}
    </div>
  );
}

export const columns: ColumnDef<CustomerRecord>[] = [
  {
    id: "expand",
    cell: ({ row }) => {
      const toggleExpand = (e: React.MouseEvent<HTMLButtonElement>) => {
        e.stopPropagation();
        row.toggleExpanded();
      };
      return (
        <div className="flex justify-center">
          <Button
            variant="primary"
            size="sm"
            data-state={row.getIsExpanded() ? "open" : "closed"}
            onClick={toggleExpand}
          >
            {row.getIsExpanded() ? <SquareMinusIcon /> : <SquarePlusIcon />}
          </Button>
        </div>
      );
    },
  },
  {
    accessorKey: "customer",
    header: ({ column }) => (
      <DataTableColumnHeader column={column} title="Customer" />
    ),
    cell: ({ row }) => {
      const { name, email, avatar } = row.original.customer;

      return (
        <div className="flex items-center gap-3">
          <Avatar className="size-10 border border-border/60">
            <AvatarFallback
              className={cn(
                "text-xs font-semibold uppercase",
                getAvatarColor(avatar || name),
              )}
            >
              {getInitials(name)}
            </AvatarFallback>
          </Avatar>
          <div className="flex flex-col items-start gap-0.5">
            <span className="text-sm font-medium">{name}</span>
          </div>
          <span className="text-xs text-muted-foreground">{email}</span>
        </div>
      );
    },
    enableSorting: false,
    enableHiding: false,
  },
  {
    accessorKey: "total",
    header: ({ column }) => (
      <DataTableColumnHeader column={column} title="Total" />
    ),
    cell: ({ row }) => (
      <span className="text-sm font-semibold tabular-nums">
        {currencyFormatter.format(row.original.total)}
      </span>
    ),
    meta: { align: "right", className: "tabular-nums" },
    enableSorting: true,
  },
  {
    accessorKey: "status",
    header: ({ column }) => (
      <DataTableColumnHeader column={column} title="Status" />
    ),
    cell: ({ row }) => {
      const status = row.original.status;
      const statusMeta = getOrderStatusMeta(status.label);
      const StatusIcon = statusMeta?.icon;

      return (
        <Badge
          variant="outline"
          className={cn("gap-1", getStatusBadgeClasses(status.variant))}
        >
          {StatusIcon ? <StatusIcon className="size-3" /> : null}
          <span className="text-xs font-medium">{status.label}</span>
        </Badge>
      );
    },
    enableSorting: false,
  },
  {
    accessorKey: "totalItems",
    header: ({ column }) => (
      <DataTableColumnHeader column={column} title="Items" />
    ),
    cell: ({ row }) => (
      <span className="text-sm text-muted-foreground">
        {row.original.totalItems}{" "}
        {row.original.totalItems === 1 ? "item" : "items"}
      </span>
    ),
    meta: { align: "right" },
    enableSorting: true,
  },
];

export function DataTable22() {
  const { table } = useDataTable({
    data: validatedData,
    columns,
    getRowId: (row) => row.id,
  });

  return (
    <section className="py-2">
      <div className="container">
        <div className="w-full">
          <div className="mb-8 text-left">
            <h2 className="text-2xl font-bold tracking-tight">
              Data table with sub data table
            </h2>
            <p className="mt-2 text-muted-foreground">
              A data table with comprehensive column controls including sorting,
              pinning, moving, and visibility management
              {/* Monitor every customer&apos;s latest order status and spend,
              complete with a detailed line-item breakdown on expand. */}
            </p>
          </div>
          <div className="overflow-hidden rounded-md border">
            <Table>
              <TableHeader>
                {table.getHeaderGroups().map((headerGroup) => (
                  <TableRow key={headerGroup.id}>
                    {headerGroup.headers.map((header) => {
                      return (
                        <TableHead key={header.id} colSpan={header.colSpan}>
                          {header.isPlaceholder
                            ? null
                            : flexRender(
                                header.column.columnDef.header,
                                header.getContext(),
                              )}
                        </TableHead>
                      );
                    })}
                  </TableRow>
                ))}
              </TableHeader>
              <TableBody>
                {table.getRowModel().rows?.length ? (
                  table.getRowModel().rows.map((row) => (
                    <React.Fragment key={row.id}>
                      <TableRow data-state={row.getIsSelected() && "selected"}>
                        {row.getVisibleCells().map((cell) => (
                          <TableCell key={cell.id}>
                            {flexRender(
                              cell.column.columnDef.cell,
                              cell.getContext(),
                            )}
                          </TableCell>
                        ))}
                      </TableRow>
                      {row.getIsExpanded() && (
                        <TableRow className="bg-muted/30 transition-colors">
                          <TableCell className="p-0" colSpan={columns.length}>
                            <OrderItemsSubTable items={row.original.items} />
                          </TableCell>
                        </TableRow>
                      )}
                    </React.Fragment>
                  ))
                ) : (
                  <TableRow>
                    <TableCell
                      colSpan={columns.length}
                      className="h-24 text-center"
                    >
                      No results.
                    </TableCell>
                  </TableRow>
                )}
              </TableBody>
            </Table>
          </div>
        </div>
      </div>
    </section>
  );
}

data-table26.source:
"use client";

import * as React from "react";
import {
  type ColumnDef,
  type Header,
  type HeaderGroup,
  type Row,
  type Cell,
  flexRender,
  getCoreRowModel,
  getSortedRowModel,
  useReactTable,
  type SortingState,
} from "@tanstack/react-table";
import {
  ArrowDown,
  ArrowLeft,
  ArrowRight,
  ArrowUp,
  ChevronsUpDown,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";

export type TransactionRow = {
  id: string;
  date: string;
  description: string;
  amount: string;
  status: string;
  category: string;
};

const defaultData: TransactionRow[] = [
  {
    id: "1",
    date: "2024-01-15",
    description: "Payment received",
    amount: "$1,200.00",
    status: "Completed",
    category: "Income",
  },
  {
    id: "2",
    date: "2024-01-14",
    description: "Office supplies",
    amount: "-$89.50",
    status: "Pending",
    category: "Expense",
  },
  {
    id: "3",
    date: "2024-01-13",
    description: "Subscription",
    amount: "-$29.99",
    status: "Completed",
    category: "Expense",
  },
  {
    id: "4",
    date: "2024-01-12",
    description: "Invoice #1024",
    amount: "$450.00",
    status: "Completed",
    category: "Income",
  },
  {
    id: "5",
    date: "2024-01-11",
    description: "Refund",
    amount: "$50.00",
    status: "Completed",
    category: "Income",
  },
];

const statusVariant = (s: string) =>
  s === "Completed" ? "positive" : "warning";

export function DataTable26({
  data = defaultData,
}: {
  data?: TransactionRow[];
}) {
  const scrollRef = React.useRef<HTMLDivElement>(null);
  const [sorting, setSorting] = React.useState<SortingState>([]);
  const [rowSelection, setRowSelection] = React.useState({});

  const scroll = (dir: "left" | "right") => {
    if (!scrollRef.current) return;
    const step = 120;
    scrollRef.current.scrollBy({
      left: dir === "left" ? -step : step,
      behavior: "smooth",
    });
  };

  const columns: ColumnDef<TransactionRow>[] = React.useMemo(
    () => [
      {
        id: "select",
        header: ({ table }) => (
          <Checkbox
            checked={table.getIsAllPageRowsSelected()}
            onCheckedChange={(v) => table.toggleAllPageRowsSelected(!!v)}
            aria-label="Select all"
          />
        ),
        cell: ({ row }) => (
          <Checkbox
            checked={row.getIsSelected()}
            onCheckedChange={(v) => row.toggleSelected(!!v)}
            aria-label="Select row"
          />
        ),
      },
      {
        accessorKey: "date",
        header: "Date",
        cell: ({ row }) => (
          <span className="whitespace-nowrap">{row.original.date}</span>
        ),
      },
      { accessorKey: "description", header: "Description" },
      {
        accessorKey: "amount",
        header: "Amount",
        cell: ({ row }) => (
          <span className="tabular-nums font-medium">
            {row.original.amount}
          </span>
        ),
      },
      {
        accessorKey: "status",
        header: "Status",
        cell: ({ row }) => (
          <Badge
            variant={
              statusVariant(row.original.status) as "positive" | "warning"
            }
          >
            {row.original.status}
          </Badge>
        ),
      },
      { accessorKey: "category", header: "Category" },
    ],
    [],
  );

  const table = useReactTable({
    data,
    columns,
    state: { sorting, rowSelection },
    onSortingChange: setSorting,
    onRowSelectionChange: setRowSelection,
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: getSortedRowModel(),
  });

  return (
    <div className="space-y-4 rounded-lg border border-border bg-background p-4">
      <div>
        <h2 className="text-lg font-semibold">Transactions</h2>
        <p className="text-sm text-muted-foreground">
          Sticky columns and scroll controls.
        </p>
      </div>
      <div className="flex items-center gap-1">
        <Button
          variant="secondary"
          size="sm"
          className="h-8 w-8 shrink-0"
          onClick={() => scroll("left")}
          aria-label="Scroll left"
        >
          <ArrowLeft className="size-4" />
        </Button>
        <div
          ref={scrollRef}
          className="min-w-0 flex-1 overflow-x-auto rounded-md border border-border"
        >
          <Table>
            <TableHeader>
              {table
                .getHeaderGroups()
                .map((headerGroup: HeaderGroup<TransactionRow>) => (
                  <TableRow key={headerGroup.id} className="bg-muted/50">
                    {headerGroup.headers.map(
                      (header: Header<TransactionRow, unknown>, i) => {
                        const sticky = i < 2;
                        const canSort = header.column.getCanSort();
                        const sorted = header.column.getIsSorted();
                        return (
                          <TableHead
                            key={header.id}
                            className={
                              sticky
                                ? "sticky left-0 z-10 bg-muted/90 shadow-[2px_0_4px_-2px_rgba(0,0,0,0.1)]"
                                : ""
                            }
                            style={sticky ? { minWidth: 100 } : undefined}
                          >
                            {canSort ? (
                              <Button
                                variant="primary"
                                size="sm"
                                className="-ml-3 h-8 gap-1"
                                onClick={() =>
                                  header.column.toggleSorting(sorted === "asc")
                                }
                              >
                                {header.isPlaceholder
                                  ? null
                                  : flexRender(
                                      header.column.columnDef.header,
                                      header.getContext(),
                                    )}
                                {sorted === "desc" ? (
                                  <ArrowDown className="size-4" />
                                ) : sorted === "asc" ? (
                                  <ArrowUp className="size-4" />
                                ) : (
                                  <ChevronsUpDown className="size-4 opacity-50" />
                                )}
                              </Button>
                            ) : header.isPlaceholder ? null : (
                              flexRender(
                                header.column.columnDef.header,
                                header.getContext(),
                              )
                            )}
                          </TableHead>
                        );
                      },
                    )}
                  </TableRow>
                ))}
            </TableHeader>
            <TableBody>
              {table.getRowModel().rows.map((row: Row<TransactionRow>) => (
                <TableRow
                  key={row.id}
                  data-state={row.getIsSelected() && "selected"}
                >
                  {row
                    .getVisibleCells()
                    .map((cell: Cell<TransactionRow, unknown>, i) => (
                      <TableCell
                        key={cell.id}
                        className={
                          i < 2
                            ? "sticky left-0 z-10 bg-background shadow-[2px_0_4px_-2px_rgba(0,0,0,0.1)]"
                            : ""
                        }
                        style={i < 2 ? { minWidth: 100 } : undefined}
                      >
                        {flexRender(
                          cell.column.columnDef.cell,
                          cell.getContext(),
                        )}
                      </TableCell>
                    ))}
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </div>
        <Button
          variant="secondary"
          size="sm"
          className="h-8 w-8 shrink-0"
          onClick={() => scroll("right")}
          aria-label="Scroll right"
        >
          <ArrowRight className="size-4" />
        </Button>
      </div>
    </div>
  );
}

data-table27.source:
"use client";

import * as React from "react";
import {
  type ColumnDef,
  type Header,
  type HeaderGroup,
  type Row,
  type Cell,
  flexRender,
  getCoreRowModel,
  getSortedRowModel,
  useReactTable,
  type SortingState,
} from "@tanstack/react-table";
import {
  ArrowDown,
  ArrowUp,
  ChevronsUpDown,
  MoreHorizontal,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";

export type VirtualRow = {
  id: string;
  name: string;
  status: string;
  role: string;
  amount: string;
};

const defaultData: VirtualRow[] = Array.from({ length: 20 }, (_, i) => ({
  id: String(i + 1),
  name: `Record ${i + 1}`,
  status: i % 3 === 0 ? "Active" : i % 3 === 1 ? "Pending" : "Completed",
  role: i % 2 === 0 ? "Admin" : "User",
  amount: `$${(i + 1) * 100}`,
}));

export function DataTable27({ data = defaultData }: { data?: VirtualRow[] }) {
  const [sorting, setSorting] = React.useState<SortingState>([]);
  const [rowSelection, setRowSelection] = React.useState({});

  const columns: ColumnDef<VirtualRow>[] = React.useMemo(
    () => [
      {
        id: "select",
        header: ({ table }) => (
          <Checkbox
            checked={table.getIsAllPageRowsSelected()}
            onCheckedChange={(v) => table.toggleAllPageRowsSelected(!!v)}
            aria-label="Select all"
          />
        ),
        cell: ({ row }) => (
          <Checkbox
            checked={row.getIsSelected()}
            onCheckedChange={(v) => row.toggleSelected(!!v)}
            aria-label="Select row"
          />
        ),
      },
      { accessorKey: "name", header: "Name" },
      {
        accessorKey: "status",
        header: "Status",
        cell: ({ row }) => (
          <Badge variant="secondary">{row.original.status}</Badge>
        ),
      },
      { accessorKey: "role", header: "Role" },
      {
        accessorKey: "amount",
        header: "Amount",
        cell: ({ row }) => (
          <span className="tabular-nums">{row.original.amount}</span>
        ),
      },
      {
        id: "actions",
        cell: ({ row }) => (
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button variant="secondary" size="sm" className="h-8 w-8 p-0">
                <MoreHorizontal className="size-4" />
                <span className="sr-only">Actions</span>
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end">
              <DropdownMenuItem>Edit</DropdownMenuItem>
              <DropdownMenuItem>View</DropdownMenuItem>
              <DropdownMenuItem>Copy ID</DropdownMenuItem>
            </DropdownMenuContent>
          </DropdownMenu>
        ),
      },
    ],
    [],
  );

  const table = useReactTable({
    data,
    columns,
    state: { sorting, rowSelection },
    onSortingChange: setSorting,
    onRowSelectionChange: setRowSelection,
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: getSortedRowModel(),
  });

  return (
    <div className="space-y-4 rounded-lg border border-border bg-background p-4">
      <div>
        <h2 className="text-lg font-semibold">Virtualized table</h2>
        <p className="text-sm text-muted-foreground">
          Fixed height, sortable, row selection, row actions.
        </p>
      </div>
      <div className="max-h-[360px] overflow-auto rounded-md border border-border">
        <Table>
          <TableHeader>
            {table
              .getHeaderGroups()
              .map((headerGroup: HeaderGroup<VirtualRow>) => (
                <TableRow
                  key={headerGroup.id}
                  className="sticky top-0 bg-muted/80"
                >
                  {headerGroup.headers.map(
                    (header: Header<VirtualRow, unknown>) => {
                      const canSort = header.column.getCanSort();
                      const sorted = header.column.getIsSorted();
                      return (
                        <TableHead key={header.id}>
                          {canSort &&
                          header.id !== "select" &&
                          header.id !== "actions" ? (
                            <Button
                              variant="primary"
                              size="sm"
                              className="-ml-3 h-8 gap-1"
                              onClick={() =>
                                header.column.toggleSorting(sorted === "asc")
                              }
                            >
                              {header.isPlaceholder
                                ? null
                                : flexRender(
                                    header.column.columnDef.header,
                                    header.getContext(),
                                  )}
                              {sorted === "desc" ? (
                                <ArrowDown className="size-4" />
                              ) : sorted === "asc" ? (
                                <ArrowUp className="size-4" />
                              ) : (
                                <ChevronsUpDown className="size-4 opacity-50" />
                              )}
                            </Button>
                          ) : header.isPlaceholder ? null : (
                            flexRender(
                              header.column.columnDef.header,
                              header.getContext(),
                            )
                          )}
                        </TableHead>
                      );
                    },
                  )}
                </TableRow>
              ))}
          </TableHeader>
          <TableBody>
            {table.getRowModel().rows.map((row: Row<VirtualRow>) => (
              <TableRow
                key={row.id}
                data-state={row.getIsSelected() && "selected"}
              >
                {row
                  .getVisibleCells()
                  .map((cell: Cell<VirtualRow, unknown>) => (
                    <TableCell key={cell.id}>
                      {flexRender(
                        cell.column.columnDef.cell,
                        cell.getContext(),
                      )}
                    </TableCell>
                  ))}
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </div>
    </div>
  );
}

