  )
}

function DropdownMenuCheckboxItem({
  className,
  children,
  checked,
  ...props
}: React.ComponentProps<typeof DropdownMenuPrimitive.CheckboxItem>) {
  return (
    <DropdownMenuPrimitive.CheckboxItem
      data-slot="dropdown-menu-checkbox-item"
      className={cn(
        "text-primary focus:bg-accent focus:text-accent-foreground relative flex cursor-default items-center gap-2 rounded-sm py-1.5 pr-2 pl-8 text-sm outline-hidden select-none data-[disabled]:pointer-events-none data-[disabled]:opacity-50 [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*='size-'])]:size-4",
        className
      )}
      checked={checked}
      {...props}
    >
      <span className="pointer-events-none absolute left-2 flex size-3.5 items-center justify-center">
        <DropdownMenuPrimitive.ItemIndicator>
          <CheckIcon className="size-4" />
        </DropdownMenuPrimitive.ItemIndicator>
      </span>
      {children}
    </DropdownMenuPrimitive.CheckboxItem>
  )
}

function DropdownMenuRadioItem({
  className,
  children,
  ...props
}: React.ComponentProps<typeof DropdownMenuPrimitive.RadioItem>) {
  return (
    <DropdownMenuPrimitive.RadioItem
      data-slot="dropdown-menu-radio-item"
      className={cn(
        "text-primary focus:bg-accent focus:text-accent-foreground relative flex cursor-default items-center gap-2 rounded-sm py-1.5 pr-2 pl-8 text-sm outline-hidden select-none data-[disabled]:pointer-events-none data-[disabled]:opacity-50 [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*='size-'])]:size-4",
        className
      )}
      {...props}
    >
      <span className="pointer-events-none absolute left-2 flex size-3.5 items-center justify-center">
        <DropdownMenuPrimitive.ItemIndicator>
          <CircleIcon className="size-2 fill-current" />
        </DropdownMenuPrimitive.ItemIndicator>
      </span>
      {children}
    </DropdownMenuPrimitive.RadioItem>
  )
}

function DropdownMenuLabel({
  className,
  inset,
  ...props
}: React.ComponentProps<typeof DropdownMenuPrimitive.Label> & {
  inset?: boolean
}) {
  return (
    <DropdownMenuPrimitive.Label
      data-slot="dropdown-menu-label"
      data-inset={inset}
      className={cn(
        "text-menu-heading px-2 py-1.5 text-sm font-medium data-[inset]:pl-8",
        className
      )}
      {...props}
    />
  )
}

function DropdownMenuSeparator({
  className,
  ...props
}: React.ComponentProps<typeof DropdownMenuPrimitive.Separator>) {
  return (
    <DropdownMenuPrimitive.Separator
      data-slot="dropdown-menu-separator"
      className={cn("bg-border -mx-1 my-1 h-px", className)}
      {...props}
    />
  )
}

function DropdownMenuShortcut({
  className,
  ...props
}: React.ComponentProps<"span">) {
  return (
    <span
      data-slot="dropdown-menu-shortcut"
      className={cn(
        "text-primary ml-auto text-xs tracking-widest",
        className
      )}
      {...props}
    />
  )
}

export {
  DropdownMenu,
  DropdownMenuTrigger,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuCheckboxItem,
  DropdownMenuRadioItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuShortcut,
  DropdownMenuGroup,
  DropdownMenuPortal,
  DropdownMenuSub,
  DropdownMenuSubContent,
  DropdownMenuSubTrigger,
  DropdownMenuRadioGroup,
}

field-mapping-1.source:
"use client";

import * as React from "react";
import { Upload, ArrowRight, Save, X } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Combobox } from "@/components/ui/combobox";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";

const sourceColumns = ["First Name", "Last Name", "Email", "Company"];
const targetFields = ["firstName", "lastName", "email", "company"];

export function FieldMapping1() {
  const [mappingOpen, setMappingOpen] = React.useState(false);
  const [mapping, setMapping] = React.useState<Record<string, string>>({});
  const [previewColumn, setPreviewColumn] = React.useState<string | null>(null);

  const previewSamples: Record<string, string[]> = {
    "First Name": ["John", "Jane", "Alex"],
    "Last Name": ["Doe", "Smith", "Chen"],
    "Email": ["john@example.com", "jane@example.com", "alex@example.com"],
    "Company": ["Acme", "Beta", "Gamma"],
  };

  return (
    <div className="rounded-lg border border-border bg-background p-6">
      <div className="relative min-h-[200px]">
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>Column A</TableHead>
              <TableHead>Column B</TableHead>
              <TableHead>Column C</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            <TableRow>
              <TableCell colSpan={3} className="h-24 text-center text-muted-foreground">
                No data imported
              </TableCell>
            </TableRow>
          </TableBody>
        </Table>
        <div className="absolute inset-0 flex items-center justify-center rounded-lg bg-background/80 backdrop-blur-sm">
          <Dialog open={mappingOpen} onOpenChange={setMappingOpen}>
            <DialogTrigger asChild>
              <Button variant="secondary" size="sm" className="gap-2">
                <Upload className="size-4" />
                Browse files
              </Button>
            </DialogTrigger>
            <DialogContent className="max-w-2xl" showClose={true}>
              <DialogHeader className="flex flex-row items-center justify-between gap-4">
                <DialogTitle>Map columns to fields</DialogTitle>
                <div className="flex gap-2">
                  <Button variant="primary" size="sm" onClick={() => setMappingOpen(false)}>
                    <X className="size-4" />
                    Exit
                  </Button>
                  <Button variant="secondary" size="sm">
                    <Save className="size-4" />
                    Save
                  </Button>
                </div>
              </DialogHeader>
              <div className="grid gap-6 sm:grid-cols-2">
                <div className="space-y-4">
                  <p className="text-xs font-medium text-muted-foreground">Source columns</p>
                  <div className="space-y-2">
                    {sourceColumns.map((col) => (
                      <div
                        key={col}
                        className="flex items-center justify-between gap-4 rounded-md border border-border bg-muted/30 px-3 py-2"
                      >
                        <Badge variant="secondary">{col}</Badge>
                        <ArrowRight className="size-4 shrink-0 text-muted-foreground" />
                        <div className="min-w-0 flex-1">
                          <Combobox
                            items={targetFields.map((f) => ({ value: f, label: f }))}
                            value={mapping[col]}
                            onValueChange={(v) => {
                              setMapping((prev) => ({ ...prev, [col]: v }));
                              setPreviewColumn(col);
                            }}
                            placeholder="Select field..."
                          />
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
                <div className="rounded-lg border border-border bg-muted/30 p-4">
                  <p className="mb-2 text-xs font-medium text-muted-foreground">Preview</p>
                  {previewColumn && previewSamples[previewColumn] ? (
                    <ul className="space-y-1 text-sm">
                      {previewSamples[previewColumn].map((val, i) => (
                        <li key={i} className="truncate font-mono text-muted-foreground">{val}</li>
                      ))}
                    </ul>
                  ) : (
                    <p className="text-sm text-muted-foreground">Select a column to see sample values.</p>
                  )}
                </div>
              </div>
            </DialogContent>
          </Dialog>
        </div>
      </div>
    </div>
  );
}

field-merging-1.source:
"use client";

import * as React from "react";
import { Merge } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
  DialogFooter,
} from "@/components/ui/dialog";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";

const users = [
  {
    id: "1",
    name: "Alex Chen",
    company: "Acme Inc",
    role: "Admin",
    email: "alex@example.com",
  },
  {
    id: "2",
    name: "Alex Chen",
    company: "Acme Corp",
    role: "Member",
    email: "a.chen@acme.com",
  },
  {
    id: "3",
    name: "Sam Wilson",
    company: "Beta Co",
    role: "Editor",
    email: "sam@example.com",
  },
];

const fieldKeys = ["name", "company", "role", "email"] as const;

export function FieldMerging1() {
  const [selected, setSelected] = React.useState<Set<string>>(new Set());
  const [mergeOpen, setMergeOpen] = React.useState(false);
  const [mergedField, setMergedField] = React.useState<Record<string, string>>(
    {},
  );

  const selectedUsers = users.filter((u) => selected.has(u.id));
  const canMerge = selectedUsers.length >= 2;

  const setRowSelected = (id: string, checked: boolean) => {
    setSelected((prev) => {
      const next = new Set(prev);
      if (checked) next.add(id);
      else next.delete(id);
      return next;
    });
  };

  const getMergedValue = (key: string) => {
    const chosen = mergedField[key];
    if (chosen) {
      const user = selectedUsers.find((u) => u.id === chosen);
      return user ? (user as Record<string, string>)[key] : "";
    }
    return selectedUsers[0]
      ? (selectedUsers[0] as Record<string, string>)[key]
      : "";
  };

  React.useEffect(() => {
    if (!mergeOpen) return;
    const initialSelected = users.filter((u) => selected.has(u.id));
    if (initialSelected.length >= 2) {
      setMergedField(
        Object.fromEntries(fieldKeys.map((k) => [k, initialSelected[0].id])),
      );
    }
  }, [mergeOpen]);

  return (
    <div className="rounded-lg border border-border bg-background p-6">
      <div className="mb-4 flex items-center justify-between">
        <h2 className="text-lg font-semibold">Users</h2>
        <Dialog open={mergeOpen} onOpenChange={setMergeOpen}>
          <DialogTrigger asChild>
            <Button
              variant="secondary"
              size="sm"
              className="gap-2"
              disabled={!canMerge}
            >
              <Merge className="size-4" />
              Merge selected
            </Button>
          </DialogTrigger>
          <DialogContent className="max-w-4xl max-h-[90vh] w-[calc(100vw-2rem)] overflow-y-auto">
            <DialogHeader>
              <DialogTitle>Merge duplicate records</DialogTitle>
            </DialogHeader>
            <div className="grid min-w-0 gap-6 sm:grid-cols-2">
              <div className="min-w-0 space-y-4 rounded-lg bg-muted/50 p-4">
                <p className="text-xs font-medium text-muted-foreground">
                  Source records
                </p>
                {selectedUsers.slice(0, 2).map((u) => (
                  <div
                    key={u.id}
                    className="flex min-w-0 items-center gap-3 rounded-md border border-border bg-background p-3"
                  >
                    <Avatar className="size-10 shrink-0">
                      <AvatarFallback>
                        {u.name
                          .split(" ")
                          .map((n) => n[0])
                          .join("")}
                      </AvatarFallback>
                    </Avatar>
                    <div className="min-w-0 flex-1 overflow-hidden text-sm">
                      <p className="truncate font-medium">{u.name}</p>
                      <p className="truncate text-muted-foreground">
                        {u.company} · {u.email}
                      </p>
                    </div>
                  </div>
                ))}
              </div>
              <div className="min-w-0 space-y-4">
                <p className="text-xs font-medium text-muted-foreground">
                  Choose value per field
                </p>
                <div className="grid min-w-0 gap-3">
                  {fieldKeys.map((key) => (
                    <div
                      key={key}
                      className="flex min-w-0 flex-col gap-2 sm:flex-row sm:items-center sm:justify-between sm:gap-4"
                    >
                      <label className="shrink-0 text-sm font-medium capitalize">
                        {key}
                      </label>
                      <RadioGroup
                        value={mergedField[key] ?? ""}
                        onValueChange={(id) =>
                          setMergedField((prev) => ({ ...prev, [key]: id }))
                        }
                        className="flex min-w-0 flex-wrap gap-4"
                      >
                        {selectedUsers.slice(0, 2).map((u) => (
                          <label
                            key={u.id}
                            className="flex min-w-0 max-w-full cursor-pointer items-center gap-2 text-sm"
                          >
                            <RadioGroupItem value={u.id} className="shrink-0" />
                            <span className="truncate">
                              {(u as Record<string, string>)[key]}
                            </span>
                          </label>
                        ))}
                      </RadioGroup>
                    </div>
                  ))}
                </div>
              </div>
            </div>
            <div className="min-w-0 rounded-lg border border-border bg-muted/30 p-4">
              <p className="mb-2 text-xs font-medium text-muted-foreground">
                Merged preview
              </p>
              <div className="flex min-w-0 items-center gap-3">
                <Avatar className="size-10 shrink-0">
                  <AvatarFallback>
                    {getMergedValue("name")
                      .split(" ")
                      .map((n: string) => n[0])
                      .join("")}
                  </AvatarFallback>
                </Avatar>
                <div className="min-w-0 flex-1 overflow-hidden text-sm">
                  <p className="truncate font-medium">
                    {getMergedValue("name")}
                  </p>
                  <p className="truncate text-muted-foreground">
                    {getMergedValue("company")} · {getMergedValue("email")}
                  </p>
                  <Badge variant="secondary" className="mt-1">
                    {getMergedValue("role")}
                  </Badge>
                </div>
              </div>
            </div>
            <DialogFooter>
              <Button
                variant="primary"
                size="sm"
                onClick={() => setMergeOpen(false)}
              >
                Cancel
              </Button>
              <Button variant="secondary" size="sm">
                Merge records
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      </div>
      <Table>
        <TableHeader>
          <TableRow>
            <TableHead className="w-10" />
            <TableHead>Name</TableHead>
            <TableHead>Company</TableHead>
            <TableHead>Role</TableHead>
            <TableHead>Email</TableHead>
          </TableRow>
        </TableHeader>
        <TableBody>
          {users.map((user) => (
            <TableRow key={user.id}>
              <TableCell>
                <Checkbox
                  checked={selected.has(user.id)}
                  onCheckedChange={(checked) =>
                    setRowSelected(user.id, checked === true)
                  }
                />
              </TableCell>
              <TableCell>
                <div className="flex items-center gap-2">
                  <Avatar className="size-8">
                    <AvatarFallback>
                      {user.name
                        .split(" ")
                        .map((n) => n[0])
                        .join("")}
                    </AvatarFallback>
                  </Avatar>
                  {user.name}
                </div>
              </TableCell>
              <TableCell>{user.company}</TableCell>
              <TableCell>
                <Badge variant="secondary">{user.role}</Badge>
              </TableCell>
              <TableCell className="text-muted-foreground">
                {user.email}
              </TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </div>
  );
}

form.source:
"use client"

import * as React from "react"
import * as LabelPrimitive from "radix-ui"
import { Slot } from "@radix-ui/react-slot"
import {
    Controller,
    ControllerProps,
    FieldPath,
    FieldValues,
    FormProvider,
    useFormContext,
} from "react-hook-form"

import { cn } from "@/lib/utils"

const Form = FormProvider

type FormFieldContextValue<
    TFieldValues extends FieldValues = FieldValues,
    TName extends FieldPath<TFieldValues> = FieldPath<TFieldValues>,
> = {
    name: TName
}

const FormFieldContext = React.createContext<FormFieldContextValue>(
    {} as FormFieldContextValue
)

const FormField = <
    TFieldValues extends FieldValues = FieldValues,
    TName extends FieldPath<TFieldValues> = FieldPath<TFieldValues>,
>({
    ...props
}: ControllerProps<TFieldValues, TName>) => {
    return (
        <FormFieldContext.Provider value={{ name: props.name }}>
            <Controller {...props} />
        </FormFieldContext.Provider>
    )
}

const useFormField = () => {
    const fieldContext = React.useContext(FormFieldContext)
    const itemContext = React.useContext(FormItemContext)
    const { getFieldState, formState } = useFormContext()

    const fieldState = getFieldState(fieldContext.name, formState)

    if (!fieldContext) {
        throw new Error("useFormField should be used within <FormField>")
    }

    const { id } = itemContext

    return {
        id,
        name: fieldContext.name,
        formItemId: `${id}-form-item`,
        formDescriptionId: `${id}-form-item-description`,
        formMessageId: `${id}-form-item-message`,
        ...fieldState,
    }
}

type FormItemContextValue = {
    id: string
}

const FormItemContext = React.createContext<FormItemContextValue>(
    {} as FormItemContextValue
)

const FormItem = React.forwardRef<
    HTMLDivElement,
    React.HTMLAttributes<HTMLDivElement>
>(({ className, ...props }, ref) => {
    const id = React.useId()

    return (
        <FormItemContext.Provider value={{ id }}>
            <div ref={ref} className={cn("grid gap-1.5", className)} {...props} />
        </FormItemContext.Provider>
    )
})
FormItem.displayName = "FormItem"

const FormLabel = React.forwardRef<
    HTMLLabelElement,
    React.LabelHTMLAttributes<HTMLLabelElement>
>(({ className, ...props }, ref) => {
    const { error, formItemId } = useFormField()

    return (
        <label
            ref={ref}
            className={cn(
                "text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70",
                error && "text-destructive",
                className
            )}
            htmlFor={formItemId}
            {...props}
        />
    )
})
FormLabel.displayName = "FormLabel"

const FormControl = React.forwardRef<
    React.ElementRef<typeof Slot>,
    React.ComponentPropsWithoutRef<typeof Slot>
>(({ ...props }, ref) => {
    const { error, formItemId, formDescriptionId, formMessageId } = useFormField()

    return (
        <Slot
            ref={ref}
            id={formItemId}
            aria-describedby={
                !error
                    ? `${formDescriptionId}`
                    : `${formDescriptionId} ${formMessageId}`
            }
            aria-invalid={!!error}
            {...props}
        />
    )
})
FormControl.displayName = "FormControl"

const FormDescription = React.forwardRef<
    HTMLParagraphElement,
    React.HTMLAttributes<HTMLParagraphElement>
>(({ className, ...props }, ref) => {
    const { formDescriptionId } = useFormField()

    return (
        <p
            ref={ref}
            id={formDescriptionId}
            className={cn("text-muted-foreground !leading-none text-[0.8rem] mt-0 mb-1", className)}
            {...props}
        />
    )
})
FormDescription.displayName = "FormDescription"

const FormMessage = React.forwardRef<
    HTMLParagraphElement,
    React.HTMLAttributes<HTMLParagraphElement>
>(({ className, children, ...props }, ref) => {
    const { error, formMessageId } = useFormField()
    const body = error ? String(error?.message) : children

    if (!body) {
        return null
    }

    return (
        <p
            ref={ref}
            id={formMessageId}
            className={cn("text-destructive text-sm font-medium !my-0", className)}
            {...props}
        >
            {body}
        </p>
    )
})
FormMessage.displayName = "FormMessage"

export {
    useFormField,
    Form,
    FormItem,
    FormLabel,
    FormControl,
    FormDescription,
    FormMessage,
    FormField,
}

